// ===========================================
// FEED CONFIGURATION
// Add or remove feeds here. Each feed needs:
//   name: Display name of the show
//   slug: URL-friendly name (lowercase, hyphens)
//   type: 'channel' or 'playlist'
//   id: YouTube channel ID (UC...) or playlist ID (PL...)
//   category: Content category for the website
//   description: Short description of the show
// ===========================================

const feeds = [
  {
    name: 'SANS Internet Storm Center',
    slug: 'sans-isc',
    type: 'channel',
    id: 'UCGyCV0hYfv41aFeIAszil0w',
    category: 'threat-intelligence',
    description: 'Daily cybersecurity threat updates and analysis'
  },
  {
    name: 'Security Weekly',
    slug: 'security-weekly',
    type: 'channel',
    id: 'UCg--XBjJ50a9tUhTKXVPiqg',
    category: 'news',
    description: 'Enterprise security news and interviews'
  },
  {
    name: 'Defensive Podcasts',
    slug: 'defensive-podcasts',
    type: 'channel',
    id: 'UCCuFaI_nwX4ZkUCkD-1e63A',
    category: 'defense',
    description: 'Blue team and defensive security content'
  },
  {
    name: 'Risky Business',
    slug: 'risky-business',
    type: 'channel',
    id: 'UCZzIaWixWHa96R7K4c40_Dg',
    category: 'news',
    description: 'Information security news and commentary'
  },
  {
    name: 'Security Now',
    slug: 'security-now',
    type: 'channel',
    id: 'UCNbqa_9xihC8yaV2o6dlsUg',
    category: 'education',
    description: 'Deep-dive security analysis with Steve Gibson'
  },
  {
    name: 'Cybersecurity Playlist',
    slug: 'cybersecurity-playlist',
    type: 'playlist',
    id: 'PLlPkFwQHxYE5n02SOQKzZHz1UXqwrZT68',
    category: 'mixed',
    description: 'Curated cybersecurity video playlist'
  }
];

// Build RSS URLs
const items = feeds.map(feed => {
  const paramKey = feed.type === 'playlist' ? 'playlist_id' : 'channel_id';
  return {
    json: {
      ...feed,
      rss_url: `https://www.youtube.com/feeds/videos.xml?${paramKey}=${feed.id}`
    }
  };
});

return items;

// Parse YouTube RSS XML and filter out already-seen videos
// Only include videos published in the last 7 days
const xml = $input.first().json.data || $input.first().json.body || '';
const feedInfo = $('Loop Feeds').first().json;

// Get persistent storage of seen video IDs
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenVideoIds) {
  staticData.seenVideoIds = [];
}
const seen = new Set(staticData.seenVideoIds);

// Only process videos from the last 7 days
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

// Parse entries from XML using regex (n8n Code nodes don't have DOMParser)
const entries = [];
const entryRegex = /<entry>(.*?)<\/entry>/gs;
let match;

while ((match = entryRegex.exec(xml)) !== null) {
  const entry = match[1];

  const videoIdMatch = entry.match(/<yt:videoId>([^<]+)<\/yt:videoId>/);
  const titleMatch = entry.match(/<title>([^<]+)<\/title>/);
  const publishedMatch = entry.match(/<published>([^<]+)<\/published>/);
  const thumbnailMatch = entry.match(/url="(https:\/\/i[^"]+)"/);
  const descriptionMatch = entry.match(/<media:description>([\s\S]*?)<\/media:description>/);

  if (videoIdMatch) {
    const videoId = videoIdMatch[1];

    // Skip already-seen videos
    if (seen.has(videoId)) continue;

    // Skip videos older than 7 days
    const publishedDate = publishedMatch ? new Date(publishedMatch[1]) : new Date();
    if (publishedDate < sevenDaysAgo) continue;

    entries.push({
      json: {
        videoId,
        title: titleMatch ? titleMatch[1] : 'Untitled',
        published: publishedMatch ? publishedMatch[1] : new Date().toISOString(),
        thumbnail: thumbnailMatch ? thumbnailMatch[1] : '',
        description: descriptionMatch ? descriptionMatch[1].substring(0, 300) : '',
        youtube_url: `https://www.youtube.com/watch?v=${videoId}`,
        // Carry forward feed metadata
        channel: feedInfo.name,
        channel_slug: feedInfo.slug,
        category: feedInfo.category,
        feed_type: feedInfo.type
      }
    });
  }
}

// If no new videos, return empty flag
if (entries.length === 0) {
  return [{ json: { _empty: true } }];
}

return entries;

// Check if transcript was fetched successfully
const transcriptData = $input.first().json;
const videoInfo = $('Loop Videos').item.json;

const transcript = transcriptData.content || transcriptData.data || '';

if (!transcript || transcript.length < 100) {
  // No transcript available - skip this video
  return [{
    json: {
      ...videoInfo,
      _noTranscript: true,
      _skipReason: 'Transcript unavailable or too short'
    }
  }];
}

// Truncate if extremely long (safety for LLM context window)
const maxChars = 150000;
const trimmedTranscript = transcript.length > maxChars 
  ? transcript.substring(0, maxChars) + '\n\n[Transcript truncated due to length]'
  : transcript;

return [{
  json: {
    ...videoInfo,
    transcript: trimmedTranscript,
    _noTranscript: false
  }
}];

// Format the LLM summary as a Hugo markdown file and prepare for GitHub push
const videoInfo = $('Loop Videos').item.json;
const llmResponse = $input.first().json;

// Extract the summary text from the LLM response
const summary = llmResponse.choices?.[0]?.message?.content || 'Summary generation failed.';

// Build a URL-safe slug from the title
const titleSlug = videoInfo.title
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 60);

// Format date for filename and frontmatter
const pubDate = new Date(videoInfo.published);
const dateStr = pubDate.toISOString().split('T')[0]; // YYYY-MM-DD

const filename = `${dateStr}-${videoInfo.channel_slug}-${titleSlug}.md`;

// Build Hugo markdown with YAML frontmatter
const markdown = `---
title: "${videoInfo.title.replace(/"/g, '\\"')}"
date: ${pubDate.toISOString()}
draft: false
channel: "${videoInfo.channel}"
channel_slug: "${videoInfo.channel_slug}"
category: "${videoInfo.category}"
youtube_url: "${videoInfo.youtube_url}"
video_id: "${videoInfo.videoId}"
thumbnail: "${videoInfo.thumbnail}"
description: "AI-generated summary of ${videoInfo.title} from ${videoInfo.channel}"
tags: ["${videoInfo.category}"]
---

${summary}
`;

// Base64 encode for GitHub API
const base64Content = Buffer.from(markdown).toString('base64');

return [{
  json: {
    ...videoInfo,
    filename,
    markdown,
    base64Content,
    filePath: `content/episodes/${filename}`
  }
}];

// Mark video as seen in persistent static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenVideoIds) {
  staticData.seenVideoIds = [];
}

const videoId = $('Loop Videos').item.json.videoId;

if (!staticData.seenVideoIds.includes(videoId)) {
  staticData.seenVideoIds.push(videoId);
}

// Cap at 2000 entries to prevent unbounded growth
if (staticData.seenVideoIds.length > 2000) {
  staticData.seenVideoIds = staticData.seenVideoIds.slice(-2000);
}

return [{ json: { videoId, status: 'marked_as_seen', totalSeen: staticData.seenVideoIds.length } }];

// Mark rejected video as seen so it doesn't reappear
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenVideoIds) {
  staticData.seenVideoIds = [];
}

const videoId = $('Loop Videos').item.json.videoId;

if (!staticData.seenVideoIds.includes(videoId)) {
  staticData.seenVideoIds.push(videoId);
}

if (staticData.seenVideoIds.length > 2000) {
  staticData.seenVideoIds = staticData.seenVideoIds.slice(-2000);
}

return [{ json: { videoId, status: 'rejected_and_marked_seen' } }];
